"use strict";(self.webpackChunkoceanchat_devdocs=self.webpackChunkoceanchat_devdocs||[]).push([[183],{45206:n=>{n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"visions-for-oceanchat","metadata":{"permalink":"/ocean.chat.docs/zh-CN/blog/visions-for-oceanchat","source":"@site/i18n/zh-CN/docusaurus-plugin-content-blog/2025-11-26-macro-level-thoughts-on-OC/index.md","title":"OceanChat \u7545\u60f3","description":"\u8ba1\u5212","date":"2025-11-26T00:00:00.000Z","tags":[],"readingTime":1.32,"hasTruncateMarker":false,"authors":[{"name":"James","title":"Full Stack developer","url":"https://github.com/JamesWilson19970101/ocean.chat.private","page":{"permalink":"/ocean.chat.docs/zh-CN/blog/authors/james"},"socials":{"x":"https://x.com/OceanChat","github":"https://github.com/JamesWilson19970101"},"imageURL":"https://avatars.githubusercontent.com/u/188664817?s=96&v=4","key":"james"}],"frontMatter":{"slug":"visions-for-oceanchat","title":"OceanChat \u7545\u60f3","authors":"james"},"unlisted":false},"content":"![\u8ba1\u5212](./oceanchat.png)\\n\\n## \u7ec4\u7ec7\u7684\u804a\u5929\\n\\n\u9996\u5148\uff0c\u6a21\u4eff\u5176\u4ed6\u5e73\u53f0\u5b9e\u73b0\u7ec4\u7ec7\uff08\u7fa4\uff09\u804a\u5929\u529f\u80fd\u3002\\n\\n## \u7ec4\u7ec7 + \u4e2a\u4eba\u7684\u804a\u5929\\n\\n\u8003\u8651\u5982\u4f55\u8ba9\u4e2a\u4eba\u7528\u6237\u4e5f\u80fd\u8bbf\u95ee\u7ec4\u7ec7\u804a\u5929\u529f\u80fd\u3002\u8fd9\u53ef\u4ee5\u901a\u8fc7\u8d44\u6e90\u5927\u5385\u6765\u5b9e\u73b0\u3002\\n\\n\u5b8c\u6210\u8fd9\u4e24\u4e2a\u6b65\u9aa4\u540e\uff0c\u5373\u53ef\u5f00\u59cb\u76c8\u5229\u3002\\n\\n\u4f8b\u5982\uff0c\u6559\u80b2\u8d44\u6e90\uff08\u8f85\u5bfc\u8001\u5e08\u3001\u5065\u8eab\u6559\u7ec3\u7b49\uff09\u4e0e\u7528\u6237\u76f8\u7ed3\u5408\u5373\u53ef\u4ea7\u751f\u6536\u76ca\u3002\\n\\n## \u4e2a\u4eba\u804a\u5929\\n\\n\u8003\u8651\u5982\u4f55\u8ba9\u4e2a\u4eba\u7528\u6237\u4e5f\u80fd\u5b8c\u5168\u8bbf\u95ee\u4e2a\u4eba\u804a\u5929\u529f\u80fd\u3002\u8fd9\u91cc\uff0c\u6211\u4eec\u9700\u8981\u5047\u8bbe\u4e2a\u4eba\u7528\u6237\u662f\u201c\u6709\u7528\u7684\u201d\u3002\\n\\n\u5728\u5f15\u5165\u6b64\u529f\u80fd\u65f6\uff0c\u6211\u4eec\u9700\u8981\u8003\u8651\u4e2a\u4eba\u7528\u6237\u53ef\u4ee5\u4f7f\u7528\u81ea\u5df1\u7684\u7535\u8111\u4f5c\u4e3a\u670d\u52a1\u5668\u3002\\n\\n> \u4e0a\u8ff0\u8ba1\u5212\u7684\u5f00\u53d1\u8def\u7ebf\u56fe\uff1a\\n>\\n> \u7b2c\u4e00\u9636\u6bb5\uff08\u5f53\u524d\uff09\uff1a\u7eaf\u804a\u5929\\n>\\n> - \u6838\u5fc3\u67b6\u6784\uff1a\u901f\u5ea6\u6781\u5feb\uff0c\u541e\u5410\u91cf\u6781\u9ad8\u3002\\n> - \u7b56\u7565\uff1a\u4ec5\u4f7f\u7528 MongoDB \u672c\u5730\u4e8b\u52a1 + NATS JetStream\u3002\\n> - \u76ee\u6807\uff1a\u89e3\u51b3\u6d88\u606f\u4e22\u5931\u548c\u5ef6\u8fdf\u95ee\u9898\u3002\\n>\\n> \u7b2c\u4e8c\u9636\u6bb5\uff08\u6269\u5c55\uff09\uff1a\u5f15\u5165\u72b6\u6001\u4e00\u81f4\u6027\\n>\\n> - \u529f\u80fd\uff1a\u4f8b\u5982\uff0c\u201c\u81ea\u6bc1\u6d88\u606f\u201d\uff08\u9700\u8981\u6d88\u606f\u670d\u52a1\u548c\u8ba1\u5212\u4efb\u52a1\u670d\u52a1\u4e4b\u95f4\u8fdb\u884c\u7d27\u5bc6\u534f\u8c03\uff09\uff0c\u6216\u201c\u7fa4\u7ec4\u6240\u6709\u8005\u8f6c\u79fb\u671f\u95f4\u7684\u6743\u9650\u8f6c\u79fb\u201d\u3002\\n> - \u7b56\u7565\uff1a\u53ef\u4ee5\u5f15\u5165\u8f7b\u91cf\u7ea7 Saga\uff08\u4f8b\u5982\u4f7f\u7528 NestJS \u7684 Saga \u6a21\u5757\uff09\u6765\u5904\u7406\u6b64\u7c7b\u590d\u6742\u3001\u957f\u65f6\u95f4\u8fd0\u884c\u7684\u4e1a\u52a1\u6d41\u7a0b\u3002\\n>\\n> \u7b2c\u4e09\u9636\u6bb5\uff08\u5546\u4e1a\u5316\uff09\uff1a\u5f15\u5165\u73b0\u91d1\\n>\\n> - \u529f\u80fd\uff1a\u7ea2\u5305\u3001\u5c0f\u8d39\u3001\u7535\u5b50\u5546\u52a1\u3002\\n> - \u7b56\u7565\uff1a\u5fc5\u987b\u5f15\u5165 TCC \u673a\u5236\uff08\u6b64\u65f6\u60a8\u53ef\u4ee5\u8ba4\u771f\u8003\u8651\u4f7f\u7528 Seata \u7b49\u6846\u67b6\uff0c\u6216\u7f16\u5199\u81ea\u5df1\u7684 TCC \u903b\u8f91\uff09\u3002\\n\\n## AI \u751f\u6210\u7684\u4e2a\u4eba\u8d44\u6599\\n\\n\u6839\u636e\u804a\u5929\u5185\u5bb9\u751f\u6210 AI \u4e2a\u4eba\u8d44\u6599\u3002\\n\\n## \u8003\u8651\u5982\u4f55\u5b9e\u65f6\u521b\u5efa\u4e2a\u4eba\u8d44\u6599\u3002\\n\\n## \u5f15\u5165\u533a\u5757\u94fe\u6280\u672f\\n\\n\u5c06\u8d44\u6e90\u653e\u5230\u533a\u5757\u94fe\u4e0a\u3002\\n\\n## \u6784\u5efa\u865a\u62df\u4e16\u754c\\n\\n\u5c06\u8d44\u6e90\u4e0a\u94fe\u540e\uff0c\u6784\u5efa\u4e00\u4e2a\u865a\u62df\u4e16\u754c\u4ee5\u8fdb\u884c\u4ea4\u6613\u3002"}]}}')}}]);